import React, { useState, useEffect } from 'react';
import './Messages.css';
import { Avatar } from '@mui/material';
import SearchIcon from '@mui/icons-material/Search';
import SendIcon from '@mui/icons-material/Send';
import AttachFileIcon from '@mui/icons-material/AttachFile';
import ArrowBackIcon from '@mui/icons-material/ArrowBack';
import axios from 'axios';
import { useParams, useNavigate } from 'react-router-dom';

const Messages = () => {
    const { conversationId } = useParams();
    const navigate = useNavigate();
    const [conversations, setConversations] = useState([]);
    const [selectedConversation, setSelectedConversation] = useState(null);
    const [selectedTrainer, setSelectedTrainer] = useState(null);
    const [newMessage, setNewMessage] = useState('');
    const [searchTerm, setSearchTerm] = useState('');
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        // If conversationId is in URL, immediately fetch trainer info
        if (conversationId && conversationId !== 'undefined') {
            const fetchTrainerInfo = async () => {
                try {
                    const trainerResponse = await axios.get(`/api/trainers/${conversationId}`);
                    const trainer = trainerResponse.data;
                    setSelectedTrainer({
                        name: trainer.name || (trainer.firstName && trainer.lastName ? `${trainer.firstName} ${trainer.lastName}` : 'Unknown'),
                        avatar: trainer.avatar || 'https://via.placeholder.com/50',
                        trainerId: trainer._id
                    });
                } catch (error) {
                    console.error('Error fetching trainer info:', error);
                    // Fallback: try generic name
                    setSelectedTrainer({
                        name: 'Trainer',
                        avatar: 'https://via.placeholder.com/50',
                        trainerId: conversationId
                    });
                }
            };
            fetchTrainerInfo();
        }
    }, [conversationId]);

    useEffect(() => {
        // Fetch real conversations from the backend
        const fetchConversations = async () => {
            try {
                const response = await axios.get('/api/chats');
                const chats = response.data;
                
                // Format conversations data
                const formattedConversations = chats.map(chat => {
                    const otherParticipant = chat.participants.find(p => p._id !== localStorage.getItem('userId'));
                    return {
                        _id: chat._id,
                        trainerId: otherParticipant?._id,
                        name: otherParticipant?.name || 'Unknown',
                        avatar: otherParticipant?.avatar || 'https://via.placeholder.com/50',
                        lastMessage: chat.messages && chat.messages.length > 0 
                            ? chat.messages[chat.messages.length - 1].text 
                            : 'No messages yet',
                        messages: chat.messages || []
                    };
                });
                
                setConversations(formattedConversations);
                
                // If conversationId is in URL, automatically select that conversation
                if (conversationId) {
                    // First try to find by conversation ID
                    let selectedConv = formattedConversations.find(conv => conv._id === conversationId);
                    
                    // If not found by conversation ID, try to find by trainer/participant ID
                    if (!selectedConv) {
                        selectedConv = formattedConversations.find(conv => conv.trainerId === conversationId);
                    }
                    
                    if (selectedConv) {
                        setSelectedConversation(selectedConv);
                        // Don't override selectedTrainer here since it's already being fetched separately
                    }
                }
            } catch (error) {
                console.error('Error fetching conversations:', error);
                setConversations([]);
            } finally {
                setLoading(false);
            }
        };

        fetchConversations();
    }, [conversationId]);

    const selectConversation = (conversation) => {
        setSelectedConversation(conversation);
        setSelectedTrainer({
            name: conversation.name,
            avatar: conversation.avatar
        });
    };

    const sendMessage = async () => {
        if (newMessage.trim() && selectedConversation) {
            try {
                const response = await axios.post(`/api/chats/${selectedConversation._id}/messages`, {
                    text: newMessage
                });
                
                // Update the conversation with the new message
                setSelectedConversation({
                    ...selectedConversation,
                    messages: [...selectedConversation.messages, response.data]
                });
                setNewMessage('');
            } catch (error) {
                console.error('Error sending message:', error);
            }
        }
    };

    const handleKeyPress = (e) => {
        if (e.key === 'Enter') {
            sendMessage();
        }
    };

    const handleBack = () => {
        setSelectedTrainer(null);
        setSelectedConversation(null);
    };

    const filteredConversations = conversations.filter(conv => 
        conv.name.toLowerCase().includes(searchTerm.toLowerCase())
    );

    return (
        <div className="messages-page">
            {conversationId ? (
                <div className="direct-message-view">
                    <div className="dm-header">
                        <button className="back-btn" onClick={handleBack}>
                            <ArrowBackIcon />
                        </button>
                        <div className="dm-header-user">
                            {selectedTrainer && (
                                <>
                                    <Avatar 
                                        src={selectedTrainer.avatar} 
                                        alt={selectedTrainer.name}
                                        sx={{ width: 40, height: 40 }}
                                    />
                                    <div>
                                        <h2>{selectedTrainer.name}</h2>
                                        <p>Active now</p>
                                    </div>
                                </>
                            )}
                        </div>
                        <button className="more-options">⋮</button>
                    </div>
                    <div className="chat-area">
                        {selectedConversation && selectedConversation.messages.length > 0 ? (
                            selectedConversation.messages.map((message, index) => (
                                <div key={index} className={`message-bubble ${message.sender === 'You' ? 'sent' : 'received'}`}>
                                    <p>{message.text}</p>
                                </div>
                            ))
                        ) : selectedTrainer ? (
                            <div className="empty-chat">
                                <div className="empty-icon">
                                    <Avatar 
                                        src={selectedTrainer.avatar} 
                                        alt={selectedTrainer.name}
                                        sx={{ width: 100, height: 100 }}
                                    />
                                </div>
                                <h3>{selectedTrainer.name}</h3>
                                <p>Start the conversation</p>
                            </div>
                        ) : (
                            <div className="empty-chat">
                                <p>Loading...</p>
                            </div>
                        )}
                    </div>
                    <div className="message-composer">
                        <AttachFileIcon className="attach-icon" />
                        <input 
                            type="text" 
                            value={newMessage} 
                            onChange={(e) => setNewMessage(e.target.value)}
                            onKeyPress={handleKeyPress}
                            placeholder="Aa" 
                        />
                        <button onClick={sendMessage} className="send-btn">
                            <SendIcon />
                        </button>
                    </div>
                </div>
            ) : (
                <>
                    <div className="messages-sidebar">
                        <div className="sidebar-header">
                            <h1>Messages</h1>
                            <button className="new-message-btn">+</button>
                        </div>
                        <div className="search-box">
                            <SearchIcon className="search-icon" />
                            <input 
                                type="text" 
                                placeholder="Search conversations..." 
                                value={searchTerm}
                                onChange={(e) => setSearchTerm(e.target.value)}
                            />
                        </div>
                        <div className="conversations">
                            {loading ? (
                                <p className="loading">Loading conversations...</p>
                            ) : filteredConversations.length > 0 ? (
                                filteredConversations.map(conversation => (
                                    <div
                                        key={conversation._id}
                                        className={`conversation ${selectedConversation?._id === conversation._id ? 'active' : ''}`}
                                        onClick={() => selectConversation(conversation)}
                                    >
                                        <Avatar 
                                            src={conversation.avatar} 
                                            alt={conversation.name}
                                            className="avatar"
                                        />
                                        <div className="conversation-info">
                                            <h3>{conversation.name}</h3>
                                            <p>{conversation.lastMessage}</p>
                                        </div>
                                    </div>
                                ))
                            ) : (
                                <p className="no-conversations">You haven't messaged anyone yet</p>
                            )}
                        </div>
                    </div>
                    <div className="messages-main">
                        {selectedConversation ? (
                            <>
                                <div className="messages-header">
                                    <div className="header-user">
                                        <Avatar 
                                            src={selectedConversation.avatar} 
                                            alt={selectedConversation.name}
                                        />
                                        <div>
                                            <h2>{selectedConversation.name}</h2>
                                            <p>Active now</p>
                                        </div>
                                    </div>
                                    <button className="more-options">⋮</button>
                                </div>
                                <div className="chat-area">
                                    {selectedConversation.messages.length > 0 ? (
                                        selectedConversation.messages.map((message, index) => (
                                            <div key={index} className={`message-bubble ${message.sender === 'You' ? 'sent' : 'received'}`}>
                                                <p>{message.text}</p>
                                            </div>
                                        ))
                                    ) : (
                                        <div className="empty-chat">
                                            <div className="empty-icon">
                                                <Avatar 
                                                    src={selectedConversation.avatar} 
                                                    alt={selectedConversation.name}
                                                    sx={{ width: 100, height: 100 }}
                                                />
                                            </div>
                                            <h3>{selectedConversation.name}</h3>
                                            <p>Start the conversation</p>
                                        </div>
                                    )}
                                </div>
                                <div className="message-composer">
                                    <AttachFileIcon className="attach-icon" />
                                    <input 
                                        type="text" 
                                        value={newMessage} 
                                        onChange={(e) => setNewMessage(e.target.value)}
                                        onKeyPress={handleKeyPress}
                                        placeholder="Aa" 
                                    />
                                    <button onClick={sendMessage} className="send-btn">
                                        <SendIcon />
                                    </button>
                                </div>
                            </>
                        ) : (
                            <div className="no-selection">
                                <div className="selection-icon">💬</div>
                                <h3>Your messages</h3>
                                <p>Send messages to trainers and keep up with your fitness journey</p>
                            </div>
                        )}
                    </div>
                </>
            )}
        </div>
    );
};

export default Messages;
